// .env.local (local dev)
DATABASE_URL=postgresql://localhost/dev_db

// .env.production (production)
DATABASE_URL=postgresql://prod-server/prod_db
```

---

**Key Rules:**

1. ✅ Use `NEXT_PUBLIC_` for browser-safe values only
2. ❌ Never prefix secrets with `NEXT_PUBLIC_`
3. ✅ Keep `.env.local` in `.gitignore`
4. ✅ Validate required variables on startup
5. ✅ Use Server Components or API routes for secrets

**Complete implementation:**

```tsx
// app/blog/[slug]/page.tsx

// 1. Pre-render all posts at build time
export async function generateStaticParams() {
  const posts = await fetch('https://api.example.com/posts')
    .then(res => res.json());

  return posts.map(post => ({
    slug: post.slug,
  }));
}

// Generate metadata for each post
export async function generateMetadata({ params }) {
  const post = await getPost(params.slug);

  return {
    title: post.title,
    description: post.excerpt,
    openGraph: {
      title: post.title,
      description: post.excerpt,
      images: [post.image],
    },
  };
}

// 2. Fetch with revalidation
async function getPost(slug) {
  const res = await fetch(`https://api.example.com/posts/${slug}`, {
    next: { 
      revalidate: 600,  // Revalidate every 10 minutes (600 seconds)
      tags: ['posts', `post-${slug}`]  // Tags for on-demand revalidation
    }
  });

  if (!res.ok) {
    throw new Error('Failed to fetch post');
  }

  return res.json();
}

// The page component
export default async function BlogPost({ params }) {
  const post = await getPost(params.slug);

  return (
    <article className="blog-post">
      <header>
        <h1>{post.title}</h1>
        <div className="meta">
          <span>By {post.author}</span>
          <span>{new Date(post.date).toLocaleDateString()}</span>
        </div>
      </header>

      {post.image && (
        <img src={post.image} alt={post.title} />
      )}

      <div 
        className="content"
        dangerouslySetInnerHTML={{ __html: post.content }}
      />

      <footer>
        <div className="tags">
          {post.tags?.map(tag => (
            <span key={tag} className="tag">{tag}</span>
          ))}
        </div>
      </footer>
    </article>
  );
}
```

