  -d '{"type": "post", "slug": "getting-started-nextjs"}'

# 2. Revalidate all posts
curl -X POST https://yoursite.com/api/revalidate \
  -H "Content-Type: application/json" \
  -H "x-revalidate-secret: your-super-secret-token-here" \
  -d '{"type": "all-posts"}'

# 3. Revalidate specific path
curl -X POST https://yoursite.com/api/revalidate \
  -H "Content-Type: application/json" \
  -H "x-revalidate-secret: your-super-secret-token-here" \
  -d '{"path": "/blog"}'
```

